#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,a[N],f[N],deep[N];
vector<int> g[N];
void dfs1(int x){
	f[x]=1;//初始化f[x]为1
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(!deep[g[x][i]]){
			deep[g[x][i]]=deep[x]+1;//deep存储节点深度，后面会用到
			dfs1(g[x][i]);
			f[x]+=(a[g[x][i]]<a[x])*f[g[x][i]];//如果a[g[x][i]]<a[x]，加上f[g[x][i]]
		}
}
void dfs2(int x){
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(deep[g[x][i]]>deep[x] && a[g[x][i]]>a[x]){
		    //如果是节点x的子节点
		    if(a[g[x][i]]>a[x])
			    f[g[x][i]]+=f[x];
			//如果子节点的权值大于x的权值，则更新f[g[x][i]]
		    dfs2(g[x][i]);
        }
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<n;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		g[u].push_back(v);
		g[v].push_back(u);
	}
	deep[1]=1;
	dfs1(1);
	dfs2(1);
	int ans=0;
	for(int i=1;i<=n;i++)
		ans=max(ans,f[i]);
	printf("%d",ans);
	return 0;
}
